+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { isRelation } from '../relation/utils/is-relation';
+import type { Schema } from '../storage';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait, TraitRecord, TraitValue } from '../trait/types';
+import type { World } from '../world';
+
+const $aspect = Symbol('aspect');
+let aspectId = 0;
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly [$aspect]: true;
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Record<string, unknown>;
+};
+
+export type AspectValue<T extends Aspect = Aspect> = Partial<
+    UnionToIntersection<T['traits'][number] extends Trait ? TraitRecord<T['traits'][number]> : never>
+>;
+
+type UnionToIntersection<U> = (U extends unknown ? (value: U) => void : never) extends (
+    value: infer I
+) => void
+    ? I
+    : never;
+
+export function isAspect(value: unknown): value is Aspect {
+    return Boolean((value as Aspect | undefined)?.[$aspect]);
+}
+
+export function createAspect<T extends readonly [Trait, Trait, ...Trait[]]>(...inputs: T): Aspect<T> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+    for (const trait of traits) {
+        if (isRelation(trait) || trait[$internal].relation) {
+            throw new Error('Aspects cannot contain relation traits');
+        }
+        for (const field of Object.keys(trait.schema)) {
+            if (fields.has(field)) {
+                throw new Error(`Aspect traits cannot have overlapping field names: ${field}`);
+            }
+            fields.add(field);
+            schema[field] = (trait.schema as Record<string, unknown>)[field];
+        }
+    }
+
+    return Object.freeze({ [$aspect]: true as const, id: aspectId++, traits: Object.freeze(traits), schema });
+}
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(world: World, entity: Entity, aspect: Aspect): Record<string, unknown> | undefined {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    return Object.assign({}, ...aspect.traits.map((trait) => getTrait(world, entity, trait)));
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: AspectValue | ((previous: any) => AspectValue), triggerChanged = true) {
+    if (value instanceof Function) value = value(getAspect(world, entity, aspect));
+    for (const trait of aspect.traits) {
+        const fields = pickFields(trait, value);
+        if (Object.keys(fields).length) setTrait(world, entity, trait, fields, triggerChanged);
+    }
+}
+
+export function addAspect(world: World, entity: Entity, aspect: Aspect, value?: AspectValue) {
+    for (const trait of aspect.traits) {
+        if (!hasTrait(world, entity, trait)) {
+            const fields = value ? pickFields(trait, value) : undefined;
+            addTrait(world, entity, fields && Object.keys(fields).length ? [trait, fields] : trait);
+        }
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    removeTrait(world, entity, ...aspect.traits);
+}
+
+export function pickFields(trait: Trait, value: Record<string, unknown>): Record<string, unknown> {
+    const fields: Record<string, unknown> = {};
+    for (const key of Object.keys(trait.schema as Schema)) {
+        if (key in value) fields[key] = value[key];
+    }
+    return fields;
+}
