+type AspectEntry = { aspect: Aspect; traits: Trait[]; stores: Store<any>[] };
+
+function createAspectQueryResult(
+    world: World,
+    entities: Entity[],
+    query: QueryInstance,
+    params: QueryParameter[]
+) {
+    const entries: (AspectEntry | { aspect?: undefined; traits: Trait[]; stores: Store<any>[] })[] = [];
+    for (const param of params) {
+        if (isAspect(param)) {
+            const traits = param.traits.filter((trait) => trait[$internal].type !== 'tag');
+            entries.push({ aspect: param, traits, stores: traits.map((trait) => getStore(world, trait)) });
+        } else if (!isModifier(param) && !isRelationPair(param) && (param as Trait)[$internal].type !== 'tag') {
+            const trait = param as Trait;
+            entries.push({ traits: [trait], stores: [getStore(world, trait)] });
+        }
+    }
+    const results: any = Object.assign(entities, {
+        readEach(callback: any) {
+            for (let i = 0; i < entities.length; i++) callback(readAspectState(entries, entities[i]), entities[i], i);
+            return results;
+        },
+        updateEach(callback: any, options: QueryResultOptions = { changeDetection: 'auto' }) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = readAspectState(entries, entity);
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                const eid = getEntityId(entity);
+                for (let j = 0; j < entries.length; j++) {
+                    const entry = entries[j];
+                    const value = state[j];
+                    for (let k = 0; k < entry.traits.length; k++) {
+                        const trait = entry.traits[k];
+                        const ctx = trait[$internal];
+                        const next = entry.aspect ? pickFields(trait, value) : value;
+                        const changed = options.changeDetection !== 'never' && ctx.fastSetWithChangeDetection(eid, entry.stores[k], next);
+                        if (changed) setChanged(world, entity, trait);
+                        else if (options.changeDetection === 'never') ctx.fastSet(eid, entry.stores[k], next);
+                    }
+                }
+            }
+            return results;
+        },
+        useStores(callback: any) { callback(entries.flatMap((entry) => entry.stores), entities); return results; },
+        select(...selected: QueryParameter[]) { return createAspectQueryResult(world, entities, query, selected); },
+        sort(callback: any = (a: Entity, b: Entity) => getEntityId(a) - getEntityId(b)) { Array.prototype.sort.call(entities, callback); return results; },
+    });
+    return results;
+}
+
+function readAspectState(entries: (AspectEntry | { aspect?: undefined; traits: Trait[]; stores: Store<any>[] })[], entity: Entity) {
+    const eid = getEntityId(entity);
+    return entries.map((entry) => {
+        const values = entry.traits.map((trait, i) => trait[$internal].get(eid, entry.stores[i]));
+        return entry.aspect ? Object.assign({}, ...values) : values[0];
+    });
+}
